#define BLOCK_SIZE 16

__kernel void lud_diagonal(__global float* a, __local float* temp, const int size, const int offset) {
    int i = get_global_id(0);
    int j, k;

    if (i >= BLOCK_SIZE) return;

    // Load diagonal block into local memory
    for (j = 0; j < BLOCK_SIZE; j++) {
        temp[i * BLOCK_SIZE + j] = a[(offset + i) * size + offset + j];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    // Perform LU decomposition on the diagonal block
    for (int diag = 0; diag < BLOCK_SIZE; diag++) {
        if (i == diag) {
            // Update upper part of the row
            for (j = diag; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < diag; k++) {
                    sum += temp[i * BLOCK_SIZE + k] * temp[k * BLOCK_SIZE + j];
                }
                temp[i * BLOCK_SIZE + j] -= sum;
            }
            // Calculate reciprocal of diagonal element
            float inv_diag = 1.0f / temp[i * BLOCK_SIZE + i];

            // Update lower part of the column
            for (j = diag + 1; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (k = 0; k < diag; k++) {
                    sum += temp[j * BLOCK_SIZE + k] * temp[k * BLOCK_SIZE + i];
                }
                temp[j * BLOCK_SIZE + i] = (temp[j * BLOCK_SIZE + i] - sum) * inv_diag;
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write back to global memory
    for (j = 0; j < BLOCK_SIZE; j++) {
        a[(offset + i) * size + offset + j] = temp[i * BLOCK_SIZE + j];
    }
}

__kernel void lud_perimeter(__global float* a, __local float* temp_top, __local float* temp_left, __local float* temp_diag, const int size, const int offset) {
