__kernel void lud_internal(__global float* a, __local float* temp_top, __local float* temp_left, const int size, const int offset) {
    int idx_x = get_global_id(0);
    int idx_y = get_global_id(1);

    int num_blocks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (idx_x >= num_blocks * BLOCK_SIZE || idx_y >= num_blocks * BLOCK_SIZE) return;

    int block_row = idx_y / BLOCK_SIZE;
    int block_col = idx_x / BLOCK_SIZE;
    int local_row = idx_y % BLOCK_SIZE;
    int local_col = idx_x % BLOCK_SIZE;

    int r = offset + BLOCK_SIZE + block_row * BLOCK_SIZE + local_row;
    int c = offset + BLOCK_SIZE + block_col * BLOCK_SIZE + local_col;

    // We need to update A[r, c]
    // A[r, c] -= sum(L[r, k] * U[k, c]) for k in diagonal block (0..BLOCK_SIZE-1 relative to offset)
    // L[r, k] is in the bottom perimeter block (row r, col offset+k)
    // U[k, c] is in the right perimeter block (row offset+k, col c)

    // Load L row segment (from bottom perimeter)
    // L[r, offset+k] for k=0..BLOCK_SIZE-1
    for (int k = 0; k < BLOCK_SIZE; k++) {
        temp_left[local_row * BLOCK_SIZE + k] = a[r * size + offset + k];
    }

    // Load U col segment (from right perimeter)
    // U[offset+k, c] for k=0..BLOCK_SIZE-1
    for (int k = 0; k < BLOCK_SIZE; k++) {
        temp_top[k * BLOCK_SIZE + local_col] = a[(offset + k) * size + c];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += temp_left[local_row * BLOCK_SIZE + k] * temp_top[k * BLOCK_SIZE + local_col];
    }

    a[r * size + c] -= sum;
}
